mapper.sql:
SELECT T.ID, T.TYPE_ID, T.VALUE_ID, G.NAME GOODS_NAME, U.NICKNAME USER_NICKNAME, T.CONTENT, T.ADD_TIME, T.STATUS, T.USER_ID FROM MALL_COMMENT T LEFT JOIN MALL_GOODS G ON G.ID = T.VALUE_ID LEFT JOIN mall_user U ON U.ID = T.USER_ID WHERE 1=1
AND T.ID = #{params.id}
AND T.VALUE_ID = #{params.valueId}
AND T.USER_ID = #{params.userId}

mapper.select:
select count(c.id) from mall_comment c
where 1= 1

    and c.type_id = #{typeId}


    and c.value_id = #{valueId}


    and c.value_id = #{goodsId}

select count(distinct c.id) from mall_comment c
left join mall_comment_picture cp on cp.comment_id = c.id
where 1= 1 and cp.id > 0

    and c.type_id = #{typeId}


    and c.value_id = #{valueId}

select distinct c.* from mall_comment c

    left join mall_comment_picture cp on cp.comment_id = c.id

where 1 = 1

    and c.type_id = #{typeId}


    and c.value_id = #{valueId}


    and c.value_id = #{goodsId}


    and c.user_id = #{userId}


    and cp.id is not null



        order by ${sidx} ${order}


        order by id desc



    limit #{offset}, #{limit}
